                <!-- Content -->
                <div class="flex-grow min-w-0 p-4 flex items-center">
                    <p id="prompt-${r.id}" class="text-gray-300 text-sm leading-relaxed font-mono whitespace-pre-wrap select-all w-full">${r.content.replace(/</g,"&lt;").replace(/>/g,"&gt;")}</p>
                </div>

